1	// claim-office.ts
2	
3	type Step = { op: string; items: { type: string }[] };
4	
5	type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	type StepResult = { premium: number };
11	
12	type ScenarioResult = {
13	  results: StepResult[];
14	};
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	const PROCESSING_FEE = 5;
26	
27	const quoteStep = (step: Step): StepResult => {
28	  const totalBasePremium = step.items.reduce(
29	    (total, item) => total + BASE_PREMIUMS[item.type],
30	    0,
31	  );
32	  const firstInsuranceSurcharge =
33	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
34	  const premium = Math.ceil(
35	    totalBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
36	  );
37	  return { premium };
38	};
39	
40	export const processScenario = (scenario: Scenario): ScenarioResult => ({
41	  results: scenario.steps.map(quoteStep),
42	});
43

